public class ReverseString {
  public static String reverse(String s) {
    StringBuilder sb = new StringBuilder();
    for (int i = s.length() - 1; i >= 0; i--) {
      sb.append(s.charAt(i));
    }
    return sb.toString();
  }
  public static void main(String[] args) {
    System.out.println(reverse("CS106A")); // "A601SC"
  }
}

public class EmailCompare {
  public static boolean sameEmail(String a, String b) {
    if (a == null || b == null) return false;
    String na = a.trim().toLowerCase();
    String nb = b.trim().toLowerCase();
    return na.equals(nb);
  }
  public static void main(String[] args) {
    System.out.println(sameEmail("  STUDENT@stanford.edu ", "student@stanford.edu")); // true
  }
}

public class LongestWord {
  public static String longestWord(String sentence) {
    if (sentence == null || sentence.isEmpty()) return "";
    String[] words = sentence.trim().split("\\s+");
    String longest = "";
    for (String w : words) {
      String clean = w.replaceAll("[^A-Za-z']", "");
      if (clean.length() > longest.length()) longest = clean;
    }
    return longest;
  }
  public static void main(String[] args) {
    System.out.println(longestWord("Stanford's CS106A is fun!")); // "Stanford's"
  }
}
